mapper.update:
update auction
set auc_finish_price = #{bidMoney}, auc_mem_id = #{id}

where (auc_finish_price < #{bidMoney} or nvl(auc_finish_price,0) < #{bidMoney}) and auc_no = #{aucNo}

update member
set mem_balance = mem_balance + #{beforeBidMoney}
where mem_id = #{beforeId}

update member
set mem_balance = mem_balance - #{bidMoney}
where mem_id = #{id}

mapper.select:
select count(*)
from bidding_interest
where auc_no = #{aucNo} and mem_id = #{id}
